199:             msg.parts.push(MessagePart::Tool(tool));
200:         }
201:     } else {
202:         if let Some(msg) = streaming_assistant_mut(app) {
203:             msg.parts.push(MessagePart::Tool(tool.clone()));
204:         }
205:         app.pending_tool_calls.push(tool);
